import{_ as l,o as i,c as e,a9 as r}from"./chunks/framework.STMWz9Nm.js";const s=JSON.parse('{"title":"Kafka学习","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/09-Kafka学习/09-Kafka学习.md","filePath":"语言/java/09-Kafka学习/09-Kafka学习.md","lastUpdated":1777106511000}'),t={name:"语言/java/09-Kafka学习/09-Kafka学习.md"};function h(f,a,n,o,k,d){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="kafka学习" tabindex="-1">Kafka学习 <a class="header-anchor" href="#kafka学习" aria-label="Permalink to “Kafka学习”">​</a></h1><p>Kafka 是 Java 生态里非常重要的消息平台和流式数据基础设施。<br> 学习 Kafka 不只是为了会发消息和消费消息，更重要的是理解分区、副本、可靠性、顺序性和吞吐设计。</p><h2 id="专题目录" tabindex="-1">专题目录 <a class="header-anchor" href="#专题目录" aria-label="Permalink to “专题目录”">​</a></h2><ul><li><a href="./01-Kafka基础架构.html">01-Kafka基础架构</a></li><li><a href="./02-生产者与消费者.html">02-生产者与消费者</a></li><li><a href="./03-分区副本与顺序性.html">03-分区副本与顺序性</a></li><li><a href="./04-可靠性与幂等.html">04-可靠性与幂等</a></li><li><a href="./05-Kafka性能调优.html">05-Kafka性能调优</a></li></ul><h2 id="_1-学习定位" tabindex="-1">1. 学习定位 <a class="header-anchor" href="#_1-学习定位" aria-label="Permalink to “1. 学习定位”">​</a></h2><p>这一组内容聚焦 Java 系统中消息平台的核心能力。<br> 目标是让你理解 Kafka 为什么适合高吞吐消息场景，以及在生产环境里怎样保证可靠和稳定。</p><h2 id="_2-学习重点" tabindex="-1">2. 学习重点 <a class="header-anchor" href="#_2-学习重点" aria-label="Permalink to “2. 学习重点”">​</a></h2><ul><li>理解 Topic、Partition、Broker 的关系</li><li>理解生产与消费的基本链路</li><li>理解顺序性和吞吐之间的取舍</li><li>理解副本和确认机制如何影响可靠性</li><li>理解 Kafka 性能问题通常来自哪些环节</li></ul><h2 id="_3-建议顺序" tabindex="-1">3. 建议顺序 <a class="header-anchor" href="#_3-建议顺序" aria-label="Permalink to “3. 建议顺序”">​</a></h2><ol><li>Kafka基础架构</li><li>生产者与消费者</li><li>分区副本与顺序性</li><li>可靠性与幂等</li><li>Kafka性能调优</li></ol><h2 id="_4-阶段产出" tabindex="-1">4. 阶段产出 <a class="header-anchor" href="#_4-阶段产出" aria-label="Permalink to “4. 阶段产出”">​</a></h2><ul><li>一份 Kafka 架构理解笔记</li><li>一份消费模型与顺序性总结</li><li>一份可靠性配置与幂等设计笔记</li><li>一份积压与性能排查清单</li></ul><h2 id="_5-自测标准" tabindex="-1">5. 自测标准 <a class="header-anchor" href="#_5-自测标准" aria-label="Permalink to “5. 自测标准”">​</a></h2><ul><li>能解释 Kafka 为何适合高吞吐</li><li>能说明分区和副本分别解决什么问题</li><li>能说清消息可靠性与性能之间的权衡</li><li>能解释为什么消费端幂等通常不可少</li></ul>',14)])])}const c=l(t,[["render",h]]);export{s as __pageData,c as default};
